export * from "./emphasis-surface";
export * from "./intent-surface";
export * from "./size";
export * from "./surface-cursor";
export * from "./surface-shape";
export * from "./width";

import { cva, type VariantProps } from "class-variance-authority";

export const emphasisSurfaceVariants = cva(null, {
	variants: {
		emphasis: {
			low: "sfc-emphasis-low-on-low",
			medium: "sfc-emphasis-medium-on-medium",
			high: "sfc-emphasis-high-on-high",
		},
	},
	defaultVariants: {
		emphasis: "medium",
	},
});
export type EmphasisSurface = VariantProps<typeof emphasisSurfaceVariants>;

import { cva } from "class-variance-authority";

export type IntentSurface = {
	intent?: "neutral" | "accent" | "success" | "warning" | "danger" | "info";
};

type Config = {
	intent: Record<NonNullable<IntentSurface["intent"]>, string>;
};

export const intentSurfaceVariants = cva<Config>(null, {
	variants: {
		intent: {
			neutral: "sfc-color-neutral-on-neutral",
			accent: "sfc-color-accent-on-accent",
			success: "sfc-color-success-on-success",
			warning: "sfc-color-warning-on-warning",
			danger: "sfc-color-danger-on-danger",
			info: "sfc-color-info-on-info",
		},
	},
	compoundVariants: [
		{
			intent: undefined,
			className: "sfc-color-default-on-default",
		},
	],
});

export const interactiveIntentSurfaceVariants = cva<Config>(null, {
	variants: {
		intent: {
			neutral: "sfc-color-neutral-on-neutral-ia",
			accent: "sfc-color-accent-on-accent-ia",
			success: "sfc-color-success-on-success-ia",
			warning: "sfc-color-warning-on-warning-ia",
			danger: "sfc-color-danger-on-danger-ia",
			info: "sfc-color-info-on-info-ia",
		},
	},
	compoundVariants: [
		{
			intent: undefined,
			className: "sfc-color-default-on-default-ia",
		},
	],
});

import { cva, type VariantProps } from "class-variance-authority";

export const surfaceCursorVariants = cva(null, {
	variants: {
		disabled: {
			true: "cursor-not-allowed",
		},
		loading: {
			true: null,
		},
	},
	compoundVariants: [
		{ disabled: false, loading: true, className: "cursor-wait" },
		{ disabled: false, loading: false, className: "cursor-pointer" },
	],
	defaultVariants: {
		disabled: false,
		loading: false,
	},
});

export type SurfaceCursor = VariantProps<typeof surfaceCursorVariants>;

import { cva, type VariantProps } from "class-variance-authority";

export const surfaceShapeVariants = cva(null, {
	variants: {
		shape: {
			square: null,
			rounded: "sfc-rounded",
			circular: "sfc-circular",
		},
	},
	defaultVariants: {
		shape: "rounded",
	},
});

export type SurfaceShape = VariantProps<typeof surfaceShapeVariants>;

export * from "./font-size";
export * from "./font-weight";
export * from "./types";

type SizeVariants = "xs" | "s" | "m" | "l" | "xl";

export type Size = {
	size?: SizeVariants;
};

import { cva } from "class-variance-authority";
import type { Size } from "./types";

export const fontSizeVariants = cva<{
	size: Record<NonNullable<Size["size"]>, string>;
}>(null, {
	variants: {
		size: {
			xs: "fs-14d",
			s: "fs-15d",
			m: "fs-16d",
			l: "fs-17d",
			xl: "fs-18d",
		},
	},
	defaultVariants: {
		size: "m",
	},
});

import { cva } from "class-variance-authority";
import type { Size } from "./types";

